import{_ as t,o as s,c as e,a3 as i}from"./chunks/framework.CGpxwYOt.js";const f=JSON.parse('{"title":"1.10 委托","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 首先我们要先确认想要制作的道具能否登记委托。 要知道挂委托能不能挂，有些制作是不能挂委托的。按O 键，找到自己要制作的页面，如果不知道分类，在搜索栏里搜索（如：药水） 像这种亮的就是可以制","frontmatter":{"title":"1.10 委托","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 首先我们要先确认想要制作的道具能否登记委托。 要知道挂委托能不能挂，有些制作是不能挂委托的。按O 键，找到自己要制作的页面，如果不知道分类，在搜索栏里搜索（如：药水） 像这种亮的就是可以制","outline":"deep"},"headers":[],"relativePath":"life/1-10.md","filePath":"life/1-10.md","lastUpdated":1782387794000}'),u={name:"life/1-10.md"};function g(p,a,r,l,o,d){return s(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="_1-10-委托" tabindex="-1">1.10 委托 <a id="s111-f45ee460"></a> <a class="header-anchor" href="#_1-10-委托" aria-label="Permalink to &quot;1.10 委托 &lt;a id=&quot;s111-f45ee460&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-10-1制作和登记委托" tabindex="-1">1.10.1制作和登记委托 <a id="s112-d7878cc6"></a> <a class="header-anchor" href="#_1-10-1制作和登记委托" aria-label="Permalink to &quot;1.10.1制作和登记委托 &lt;a id=&quot;s112-d7878cc6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>首先我们要先确认想要制作的道具能否登记委托。</p><p>要知道挂委托能不能挂，有些制作是不能挂委托的。按O 键，找到自己要制作的页面，如果不知道分类，在搜索栏里搜索（如：药水）</p><figure class="image-flow" data-pdf-anchor="页面，如果不知道分类，在搜索栏里搜索（如：药水）"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1502.jpeg" alt="图示" loading="lazy"></figure><p>像这种亮的就是可以制作委托书的。</p><p>像这种灰色的就是不能制作委托书的。</p><p>确认好后流程如下：按下O 键唤出生产菜单栏后，选择一个要挂委托的物品。</p><p>（要确保背包内有充足的原材料）</p><figure class="image-flow" data-pdf-anchor="（要确保背包内有充足的原材料）"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1509.jpeg" alt="图示" loading="lazy"></figure><p>点完确认后背包内会出现一个委托书，点击背包的委托书唤出委托菜单栏：</p><figure class="image-flow" data-pdf-anchor="点完确认后背包内会出现一个委托书，点击背包的委托书唤出委托菜单栏："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1520.jpeg" alt="图示" loading="lazy"></figure><p>然后在红框位置调整为你希望挂上去的价格，再点击箭头处的登记即可。</p><p>一个角色同一时间只能挂5 个委托（不影响同账号其他角色）</p><h2 id="_1-10-2-接受委托" tabindex="-1">1.10.2 接受委托 <a id="s113-0f1a1c94"></a> <a class="header-anchor" href="#_1-10-2-接受委托" aria-label="Permalink to &quot;1.10.2 接受委托 &lt;a id=&quot;s113-0f1a1c94&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>玩家可以在住民会馆旁边的制作委托公告板上接受委托。</p><p>走过去会出现交互键，交互后会出现目录。</p><figure class="image-flow" data-pdf-anchor="走过去会出现交互键，交互后会出现目录"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1527.jpeg" alt="图示" loading="lazy"></figure><p>亮黄色说明熟练度达标可以制作，灰色说明熟练度不足以制作，选择一个价格满意的委托后单击亮黄色的放大镜图标，会出现以下界面：</p><figure class="image-flow" data-pdf-anchor="亮黄色说明熟练度达标可以制作，灰色说明熟练度不足以制作，选择一个价格满"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1526.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="意的委托后单击亮黄色的放大镜图标，会出现以下界面："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1532.jpeg" alt="图示" loading="lazy"></figure><p>红框内为接受该委托实际花费的（受熟练度减免的）劳动力，确认好劳动力和总领取额是否满意后，点击箭头指向的确认键即可接受委托。</p><p>然后会出现读条，读条完后会消耗劳动力，并以邮件的形式给你发放报酬。</p><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1514.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1515.jpeg" alt="图示" loading="lazy"></figure>',26)])])}const _=t(u,[["render",g]]);export{f as __pageData,_ as default};
